const bgLine=document.querySelector(".line-bg");document.addEventListener("scroll",e=>{const t=Math.round(.2*window.scrollY);bgLine.style.transform=`rotate(-${t}deg)`});const form=document.querySelector("form"),inputs=form.querySelectorAll("input"),textareas=form.querySelectorAll("textarea"),formElements=[...inputs,...textareas],focusHandler=e=>{""!==e.value?(console.dir(e),e.nextElementSibling.classList.add("focus")):e.nextElementSibling.classList.remove("focus")};form.addEventListener("submit",e=>{e.preventDefault(),console.log(formElements),formElements.forEach(e=>{""==e.value&&e.classList.contains("required")?e.parentElement.classList.add("error"):e.parentElement.classList.remove("error")})}),formElements.forEach(e=>{e.addEventListener("focus",()=>{e.parentElement.classList.add("focus-border")}),e.addEventListener("blur",()=>{e.parentElement.classList.remove("focus-border")})}),inputs.forEach(e=>{e.addEventListener("change",()=>{focusHandler(e)})});